#!/usr/bin/env python3
"""Apply script v3: MFL rate limit fixes.

Fixes for MFL 429 rate limiting during matchup results ingestion:
  - http_request_with_retries: 5s base backoff for 429 (was 1.5s)
  - Matchup results: 2.5s inter-week delay (was 1.25s)
  - Matchup results: delay BEFORE every request (not just after success)
  - Adaptive 429 cooldown: doubles delay on 429, gradually restores on success
  - Per-week progress output (week N: 5 matchups (new/exists))
  - Inter-season cooldown: 7.5s between seasons (was 2.5s)

Updates:
  src/squadvault/utils/http.py
  src/squadvault/mfl/historical_ingest.py

Run: python3 apply_mfl_rate_limit_v3.py
Then: PYTHONPATH=src python -m pytest Tests/ -q
"""

import base64
from pathlib import Path

# --- src/squadvault/utils/http.py ---
_p = Path("src/squadvault/utils/http.py")
_p.parent.mkdir(parents=True, exist_ok=True)
_p.write_bytes(base64.b64decode(""))
print(f"  wrote {_p}")

# --- src/squadvault/mfl/historical_ingest.py ---
_p = Path("src/squadvault/mfl/historical_ingest.py")
_p.parent.mkdir(parents=True, exist_ok=True)
_p.write_bytes(base64.b64decode(""))
print(f"  wrote {_p}")

print()
print("Done. Run: PYTHONPATH=src python -m pytest Tests/ -q")
print("Expected: 1174 passed, 3 skipped")
print()
print("Resume ingest (picks up where you left off — dedup protects already-ingested data):")
print("  ./scripts/py -u src/squadvault/mfl/_run_historical_ingest.py \\\\")
print("    --db .local_squadvault.sqlite --league-id 70985 \\\\")
print("    --start-year 2017 --end-year 2023 \\\\")
print("    --expected-franchises 10 --delay 2.5")
